// Update PlanCard to show DCG validation status

function PlanCard({ plan, ...props }) {
  const { data: validation } = useValidatePlan(plan.id);

  return (
    <Card>
      <CardContent>
        {/* ... existing content ... */}

        {/* DCG Validation Badge */}
        {validation && (
