## Testing Requirements

### Unit Tests

```typescript
describe("DCG-RU Integration", () => {
  describe("validateSweepPlan", () => {
    it("should detect dangerous commands in plan", async () => {
      const plan = await createTestPlan({
        actions: [
          { type: "shell", command: "rm -rf /important" },
          { type: "commit", message: "Update", files: ["*.txt"] },
        ],
      });

      const result = await validateSweepPlan(plan.id);

      expect(result.valid).toBe(false);
      expect(result.blockedCommands).toBeGreaterThan(0);
      expect(result.riskLevel).toBe("critical");

      logger.info({
        testName: "detect_dangerous_commands",
        planId: plan.id,
        blockedCommands: result.blockedCommands,
        correlationId: getCorrelationId(),
      }, "Dangerous commands detected in plan");
    });

    it("should pass validation for safe plans", async () => {
      const plan = await createTestPlan({
        actions: [
          { type: "commit", message: "Update docs", files: ["README.md"] },
        ],
      });

      const result = await validateSweepPlan(plan.id);

      expect(result.valid).toBe(true);
      expect(result.riskLevel).toBe("low");

      logger.info({
        testName: "safe_plan_validation",
        correlationId: getCorrelationId(),
      }, "Safe plan validated");
    });
  });

  describe("executeActionWithDCG", () => {
    it("should block execution of dangerous commands", async () => {
      const result = await executeActionWithDCG(
        "session_1",
        "plan_1",
        0,
        { type: "shell", command: "chmod 777 /etc/passwd" }
      );

      expect(result.success).toBe(false);
      expect(result.blockedByDCG).toBe(true);
      expect(result.blockDetails?.ruleId).toContain("filesystem");

      logger.info({
        testName: "block_dangerous_execution",
        correlationId: getCorrelationId(),
      }, "Dangerous command blocked during execution");
    });

    it("should allow execution with approved exception", async () => {
      // Create and approve exception
      const exception = await createPendingException({
        command: "test-allowed-command",
        pack: "test",
        ruleId: "test:allowed",
        reason: "Test",
        severity: "medium",
      });
      await approvePendingException(exception.shortCode, "test-user");

      const result = await executeActionWithDCG(
        "session_1",
        "plan_1",
        0,
        { type: "shell", command: "test-allowed-command" }
      );

      expect(result.success).toBe(true);
      expect(result.blockedByDCG).toBe(false);

      logger.info({
        testName: "execute_with_exception",
        correlationId: getCorrelationId(),
      }, "Command executed with approved exception");
    });
  });

  describe("createExceptionsForPlan", () => {
    it("should create exceptions for blocked commands", async () => {
      const plan = await createTestPlan({
        actions: [
          { type: "shell", command: "dangerous-command-1" },
          { type: "shell", command: "dangerous-command-2" },
        ],
      });
      await validateSweepPlan(plan.id);

      const codes = await createExceptionsForPlan(plan.id, "test-user");

      expect(codes.length).toBeGreaterThan(0);

      logger.info({
        testName: "create_exceptions",
        planId: plan.id,
        exceptionCount: codes.length,
        correlationId: getCorrelationId(),
      }, "Exceptions created for plan");
    });
  });
});
```

